export default function StatsBar({ tasks }) {
  const counts = {
    total:      tasks.length,
    pending:    tasks.filter(t => t.status === "pending").length,
    inProgress: tasks.filter(t => t.status === "in-progress").length,
    completed:  tasks.filter(t => t.status === "completed").length,
  };

  const stats = [
    { label: "Total",       value: counts.total,      color: "text-gray-900"   },
    { label: "Pending",     value: counts.pending,    color: "text-amber-600"  },
    { label: "In Progress", value: counts.inProgress, color: "text-blue-600"   },
    { label: "Completed",   value: counts.completed,  color: "text-green-600"  },
  ];

  return (
  
    <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4 mb-6">
      {stats.map(s => (
        <div key={s.label} className="bg-white rounded-2xl border border-gray-100 px-3 sm:px-5 py-4 shadow-sm text-center sm:text-left">
          <p className="text-[10px] sm:text-xs text-gray-400 font-medium uppercase tracking-wide mb-1">{s.label}</p>
          <p className={`text-2xl sm:text-3xl font-bold ${s.color}`}>{s.value}</p>
        </div>
      ))}
    </div>
  );
}
